// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "../interfaces/IPoolContracts.sol";

interface IUniswapV2Router02 {
    function swapExactETHForTokens(
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external payable returns (uint256[] memory amounts);
    function swapExactTokensForTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external returns (uint256[] memory amounts);
    function getAmountsOut(
        uint256 amountIn,
        address[] calldata path
    ) external view returns (uint256[] memory amounts);
}

interface IBurnableToken {
    function burn(uint256 amount) external;
}

interface IWUSDC {
    function deposit() external payable;
}

contract BuyAndBurnEngine is ReentrancyGuard, Ownable {
    using SafeERC20 for IERC20;
    address public dexRouter;
    address public keeper;
    uint256 public burnThreshold = 1e17;
    uint256 public maxSlippage = 5e16;
    uint256 public maxSingleBurn = 1e18;
    uint256 public minInterval = 30;
    uint256 public lastBurnTimestamp;
    uint256 public randomDelayBlocks = 3;

    mapping(address => uint256) public pendingUsdc;
    mapping(address => uint256) public totalBurned;
    mapping(address => uint256) public totalUsdcUsed;
    mapping(address => uint256) public burnCount;

    address public constant DEAD_ADDRESS = 0x000000000000000000000000000000000000dEaD;
    address public wrappedNative;

    bool public isXyloRouter;

    event TokenBurned(address indexed token, uint256 tokensBurned, uint256 usdcUsed);
    event UsdcDeposited(address indexed token, uint256 amount);

    constructor(address _dexRouter, address _keeper, bool _isXyloRouter, address _wrappedNative) Ownable(msg.sender) {
        dexRouter = _dexRouter;
        keeper = _keeper;
        isXyloRouter = _isXyloRouter;
        wrappedNative = _wrappedNative;
    }

    function deposit(address token) external payable nonReentrant {
        require(msg.value > 0, "Zero value");
        pendingUsdc[token] += msg.value;
        emit UsdcDeposited(token, msg.value);
    }

    function executeBurn(address token, uint256 minTokensOut) external nonReentrant {
        require(msg.sender == keeper, "Not keeper");
        require(pendingUsdc[token] >= burnThreshold, "Below threshold");
        require(block.timestamp >= lastBurnTimestamp + minInterval, "Too soon");

        uint256 burnAmount = pendingUsdc[token];
        if (burnAmount > maxSingleBurn) {
            burnAmount = maxSingleBurn;
        }

        pendingUsdc[token] -= burnAmount;
        lastBurnTimestamp = block.timestamp;

        uint256 expectedOut = getEstimatedTokensOut(token, burnAmount);
        uint256 minOut = (expectedOut * (1e18 - maxSlippage)) / 1e18;
        require(minTokensOut >= minOut, "slippage exceeded");

        address[] memory path = new address[](2);
        path[0] = wrappedNative;
        path[1] = token;

        uint256 tokensBought;

        if (!isXyloRouter) {
            uint256[] memory amounts = IUniswapV2Router02(dexRouter).swapExactETHForTokens{value: burnAmount}(
                minTokensOut, path, address(this), block.timestamp + 300
            );
            tokensBought = amounts[amounts.length - 1];
        } else {
            IWUSDC(wrappedNative).deposit{value: burnAmount}();
            IERC20(wrappedNative).forceApprove(dexRouter, burnAmount);
            uint256[] memory amounts = IUniswapV2Router02(dexRouter).swapExactTokensForTokens(
                burnAmount, minTokensOut, path, address(this), block.timestamp + 300
            );
            tokensBought = amounts[amounts.length - 1];
        }

        try IBurnableToken(token).burn(tokensBought) {
            totalBurned[token] += tokensBought;
        } catch {
            IERC20(token).safeTransfer(DEAD_ADDRESS, tokensBought);
            totalBurned[token] += tokensBought;
        }

        totalUsdcUsed[token] += burnAmount;
        burnCount[token] += 1;

        emit TokenBurned(token, tokensBought, burnAmount);
    }

    function setKeeper(address _keeper) external onlyOwner {
        keeper = _keeper;
    }

    function setIsXyloRouter(bool _isXyloRouter) external onlyOwner {
        isXyloRouter = _isXyloRouter;
    }

    function setWrappedNative(address _wrappedNative) external onlyOwner {
        wrappedNative = _wrappedNative;
    }

    function setDexRouter(address _dexRouter) external onlyOwner {
        dexRouter = _dexRouter;
    }

    function setBurnThreshold(uint256 _threshold) external onlyOwner {
        burnThreshold = _threshold;
    }

    function setMaxSlippage(uint256 _slippage) external onlyOwner {
        maxSlippage = _slippage;
    }

    function emergencyWithdraw(address payable to, uint256 amount) external onlyOwner nonReentrant {
        require(to != address(0));
        require(amount <= address(this).balance);
        (bool success,) = to.call{value: amount}("");
        require(success);
    }

    function emergencyWithdrawToken(address token, address to, uint256 amount) external onlyOwner nonReentrant {
        require(to != address(0));
        IERC20(token).safeTransfer(to, amount);
    }

    function getEstimatedTokensOut(address token, uint256 usdcAmount) public view returns (uint256) {
        address[] memory path = new address[](2);
        path[0] = wrappedNative;
        path[1] = token;
        uint256[] memory amounts = IUniswapV2Router02(dexRouter).getAmountsOut(usdcAmount, path);
        return amounts[amounts.length - 1];
    }

    receive() external payable {}
}

project/contracts/periphery/CreatorRewar.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

contract CreatorRewardManager is Ownable, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    struct VestingSchedule {
        uint256 totalAmount;
        uint256 claimedAmount;
        uint256 startTimestamp;
        uint256 cliffEnd;
        uint256 vestingEnd;
        bool exists;
    }

    address public bondingCurve;
    address public dexLister;

    mapping(address => mapping(address => VestingSchedule)) public vestings;
    mapping(address => uint256) public totalVestedAmount;

    event VestingCreated(address indexed asset, address indexed beneficiary, uint256 amount, uint256 cliffEnd, uint256 vestingEnd);
    event VestedTokensClaimed(address indexed asset, address indexed beneficiary, uint256 amount);

    modifier onlyBondingCurveOrDexLister() {
        require(msg.sender == bondingCurve || msg.sender == dexLister, "only bonding curve");
        _;
    }

    constructor(address _bondingCurve) Ownable(msg.sender) {
        bondingCurve = _bondingCurve;
    }

    function setBondingCurve(address _bondingCurve) external onlyOwner {
        bondingCurve = _bondingCurve;
    }

    function setDexLister(address _dexLister) external onlyOwner {
        dexLister = _dexLister;
    }

    function createVesting(
        address asset,
        address beneficiary,
        uint256 amount,
        uint256 cliffDuration,
        uint256 vestingDuration
    ) external onlyBondingCurveOrDexLister {
        require(amount > 0, "zero amount");
        require(beneficiary != address(0), "zero beneficiary");
        require(vestingDuration >= cliffDuration, "vesting < cliff");

        VestingSchedule storage v = vestings[asset][beneficiary];
        require(!v.exists, "vesting exists");

        uint256 start = block.timestamp;
        v.totalAmount = amount;
        v.claimedAmount = 0;
        v.startTimestamp = start;
        v.cliffEnd = start + cliffDuration;
        v.vestingEnd = start + vestingDuration;
        v.exists = true;

        totalVestedAmount[asset] += amount;

        emit VestingCreated(asset, beneficiary, amount, v.cliffEnd, v.vestingEnd);
    }

    function claim(address asset) external nonReentrant whenNotPaused {
        VestingSchedule storage v = vestings[asset][msg.sender];
        require(v.exists, "no vesting");

        uint256 vested = _vestedAmount(v);
        uint256 claimable = vested - v.claimedAmount;
        require(claimable > 0, "nothing to claim");

        v.claimedAmount += claimable;
        totalVestedAmount[asset] -= claimable;

        IERC20(asset).safeTransfer(msg.sender, claimable);

        emit VestedTokensClaimed(asset, msg.sender, claimable);
    }

    function claimMultiple(address[] calldata assets) external nonReentrant whenNotPaused {
        for (uint256 i = 0; i < assets.length; i++) {
            VestingSchedule storage v = vestings[assets[i]][msg.sender];
            if (!v.exists) continue;

            uint256 vested = _vestedAmount(v);
            uint256 claimable = vested - v.claimedAmount;
            if (claimable == 0) continue;

            v.claimedAmount += claimable;
            totalVestedAmount[assets[i]] -= claimable;

            IERC20(assets[i]).safeTransfer(msg.sender, claimable);

            emit VestedTokensClaimed(assets[i], msg.sender, claimable);
        }
    }

    function pendingClaim(address asset, address beneficiary) external view returns (uint256) {
        VestingSchedule storage v = vestings[asset][beneficiary];
        if (!v.exists) return 0;
        return _vestedAmount(v) - v.claimedAmount;
    }

    function vestingInfo(address asset, address beneficiary) external view returns (
        uint256 totalAmount,
        uint256 claimedAmount,
        uint256 startTimestamp,
        uint256 cliffEnd,
        uint256 vestingEnd,
        bool exists
    ) {
        VestingSchedule storage v = vestings[asset][beneficiary];
        return (v.totalAmount, v.claimedAmount, v.startTimestamp, v.cliffEnd, v.vestingEnd, v.exists);
    }

    function _vestedAmount(VestingSchedule storage v) internal view returns (uint256) {
        if (block.timestamp < v.cliffEnd) return 0;
        if (block.timestamp >= v.vestingEnd) return v.totalAmount;

        uint256 elapsed = block.timestamp - v.startTimestamp;
        return (v.totalAmount * elapsed) / (v.vestingEnd - v.startTimestamp);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function rescueTokens(address token, address to, uint256 amount) external onlyOwner {
        uint256 contractBalance = IERC20(token).balanceOf(address(this));
        uint256 protected = totalVestedAmount[token];
        require(contractBalance - protected >= amount, "insufficient unvested balance");
        IERC20(token).safeTransfer(to, amount);
    }
}

